turtle:
wdt:PhoneNumberOf a wikibase:Property ;
    schema:description "The contact phone number of the subject." ;
    rdfs:label "phone number" ;
    rdfs:domain owl:Thing ;
    rdfs:range xsd:string .

wdt:emailAddress a wikibase:Property ;
    schema:description "The email address associated with the subject." ;
    rdfs:label "email address" ;
    rdfs:domain owl:Thing ;
    rdfs:range xsd:string .

wdt:LinkedInProfileURL a wikibase:Property ;
    rdfs:label "LinkedIn profile URL" ;
    schema:description "The URL of the subject's LinkedIn profile." ;
    rdfs:domain wd:Person, wd:Organization, wd:PublicFigure ;
    rdfs:range xsd:anyURI .

wdt:GitHubProfileURL a wikibase:Property ;
    rdfs:label "GitHub profile URL" ;
    schema:description "The URL of the subject's GitHub profile." ;
    rdfs:domain wd:Person, wd:Organization, wd:SoftwareDeveloper ;
    rdfs:range xsd:anyURI .

wdt:ProfessionalRole a wikibase:Property ;
    rdfs:label "professional role" ;
    rdfs:comment "The current or most relevant professional role of the subject." ;
    rdfs:domain wd:Person ;
    rdfs:range wd:ProfessionalRoleType .

wdt:field_of_engineering a wikibase:Property ;
    rdfs:label "field of engineering" ;
    rdfs:comment "The specific branch of engineering the subject is specialized in." ;
    rdfs:domain wd:engineer, wd:engineering_discipline, wd:engineering_project ;
    rdfs:range wd:branch_of_engineering .

wdt:Location a wikibase:Property ;
    schema:description "The city and country where an educational institution is located." ;
    rdfs:label "location" ;
    rdfs:domain wd:educational_institution ;
    rdfs:range wd:location .

wdt:CGPA a wikibase:Property ;
    schema:description "The cumulative grade point average achieved in an academic program." ;
    rdfs:label "CGPA" ;
    rdfs:domain wd:AcademicProgram, wd:StudentRecord ;
    rdfs:range xsd:float .

wdt:CoreCourses a wikibase:Property ;
    schema:description "The fundamental academic courses completed in an educational program." ;
    rdfs:label "core courses" ;
    rdfs:domain wd:AcademicProgram, wd:EducationalProgram ;
    rdfs:range wd:Course, wd:AcademicCourse .

wdt:SpecializedKnowledge a wikibase:Property ;
    schema:description "The specific technical or theoretical knowledge areas developed in an educational program." ;
    rdfs:label "specialized knowledge" ;
    rdfs:domain wd:educational_program, wd:academic_degree, wd:training_course ;
    rdfs:range rdfs:Resource .

wdt:institution a wikibase:Property ;
    rdfs:label "institution" ;
    rdfs:comment "The name of the school or college where a secondary or pre-university qualification was obtained." ;
    rdfs:domain wd:Person ;
    rdfs:range wd:EducationalOrganization .

wdt:P381 a wikibase:Property ;
    schema:description "The time period over which a secondary or pre-university qualification was completed." ;
    rdfs:label "duration of program" ;
    rdfs:domain wd:educational_program, wd:academic_qualification, wd:secondary_education ;
    rdfs:range xsd:duration .

wdt:PerformancePercentage a wikibase:Property ;
    schema:description "The percentage of marks achieved in an academic qualification." ;
    rdfs:label "performance percentage" ;
    rdfs:domain wd:AcademicQualification ;
    rdfs:range xsd:float .

wdt:P39 a wikibase:Property ;
    schema:description "The time period during which a specific job role was held." ;
    rdfs:label "duration of role" ;
    rdfs:domain wd:office, wd:position_held, wd:job_title ;
    rdfs:range xsd:duration .

wdt:Responsibilities a wikibase:Property ;
    schema:description "The key tasks or duties performed in a job role." ;
    rdfs:label "responsibilities" ;
    rdfs:domain wd:JobRole, wd:Occupation, wd:Position ;
    rdfs:range rdfs:Literal .

wdt:Achievements a wikibase:Property ;
    schema:description "The notable accomplishments made in a job role." ;
    rdfs:label "achievements" ;
    rdfs:domain wd:JobRole, wd:Occupation, wd:Position ;
    rdfs:range rdfs:Literal .

wdt:SimulationTools a wikibase:Property ;
    schema:description "The software tools used for conducting simulations." ;
    rdfs:label "simulation tools" ;
    rdfs:domain wd:simulation, wd:modeling_process, wd:experiment ;
    rdfs:range wd:software_tool, wd:simulation_software, wd:computational_tool .

wdt:Algorithm a wikibase:Property ;
    schema:description "The specific machine learning or computational algorithm used." ;
    rdfs:label "algorithm" ;
    rdfs:domain wd:computational_model, wd:experiment, wd:software, wd:research_study ;
    rdfs:range wd:decision_tree, wd:neural_network, wd:svm, wd:random_forest, wd:gradient_boosting, wd:logistic_regression, wd:kmeans, wd:naive_bayes .

wdt:Tools a wikibase:Property ;
    schema:description "The specific software or frameworks used to optimize workflows" ;
    rdfs:label "tools" ;
    rdfs:domain wd:workflow, wd:process, wd:system ;
    rdfs:range wd:software, wd:framework, wd:application .

wdt:hardwarePlatforms a wikibase:Property ;
    schema:description "The specific hardware used for developing or deploying embedded systems." ;
    rdfs:label "hardware platforms" ;
    rdfs:domain wd:embedded_system, wd:software, wd:application ;
    rdfs:range wd:computer_hardware, wd:processor, wd:development_board, wd:platform .

wdt:location_of_university a wikibase:Property ;
    rdfs:label "location of university" ;
    rdfs:comment "The city where the subject's university is located." ;
    rdfs:domain wd:University ;
    rdfs:range wd:City .

wdt:P585 a wikibase:Property ;
    rdfs:label "duration of degree" ;
    rdfs:comment "The time period in which a degree was pursued." ;
    rdfs:domain wd:educational_achievement ;
    rdfs:range xsd:duration .

wdt:location_of_college a wikibase:Property ;
    rdfs:label "location of college" ;
    rdfs:comment "The city where the FSc college is located." ;
    rdfs:domain wd:FSc_college ;
    rdfs:range schema:City .

wdt:marks_percentage_in_FSc a wikibase:Property ;
    schema:description "The percentage of marks achieved in the FSc program." ;
    rdfs:label "marks percentage in FSc" ;
    rdfs:domain wd:person ;
    rdfs:range xsd:float .

wdt:country_of_school a wikibase:Property ;
    rdfs:label "country of school" ;
    rdfs:comment "The country where the matriculation school is located." ;
    rdfs:domain wd:educational_institution ;
    rdfs:range wd:country .

wdt:P123 a wikibase:Property ;
    schema:description "The time period in which the matriculation was completed." ;
    rdfs:label "duration of matriculation" ;
    rdfs:domain wd:MatriculationEvent ;
    rdfs:range xsd:duration .

wdt:MarksPercentageInMatriculation a wikibase:Property ;
    schema:description "The percentage of marks achieved in the matriculation program." ;
    rdfs:label "marks percentage in matriculation" ;
    rdfs:domain wd:Person, wd:Student ;
    rdfs:range xsd:float .

wdt:P56 a wikibase:Property ;
    schema:description "The organization where the subject is currently employed." ;
    rdfs:label "current employer" ;
    rdfs:domain wd:Person ;
    rdfs:range wd:Organization .

wdt:location_of_employer a wikibase:Property ;
    schema:description "The city where the current employer is located." ;
    rdfs:label "location of employer" ;
    rdfs:domain wd:person ;
    rdfs:range wd:city .

wdt:FocusOfWork a wikibase:Property ;
    rdfs:label "focus of work" ;
    rdfs:comment "The primary area or topic of the subject's professional activities." ;
    rdfs:domain wd:Person, wd:Organization, wd:Project ;
    rdfs:range rdfs:Resource, wd:FieldOfStudy, wd:Topic, wd:Activity .

wdt:RL_algorithm_used a wikibase:Property ;
    schema:description "The reinforcement learning algorithm used in a project." ;
    rdfs:label "RL algorithm used" ;
    rdfs:domain wd:project, wd:research_study, wd:experiment, wd:software_development ;
    rdfs:range wd:reinforcement_learning_algorithm, wd:learning_method, wd:ai_technique, wd:algorithm .

wdt:algorithm_for_positioning a wikibase:Property ;
    schema:description "The specific algorithm used to achieve a particular result in a simulation." ;
    rdfs:label "algorithm for positioning" ;
    rdfs:domain wd:simulation ;
    rdfs:range wd:algorithm .

wdt:multiAgentFrameworkName a wikibase:Property ;
    rdfs:label "multi-agent framework name" ;
    schema:description "The name of the framework used for multi-agent coordination." ;
    rdfs:domain wd:MultiAgentSystem ;
    rdfs:range xsd:string .

wdt:freelance_company a wikibase:Property ;
    schema:description "The name of the company or entity for which the subject worked as a freelancer." ;
    rdfs:label "freelance company" ;
    rdfs:domain wd:Person ;
    rdfs:range wd:Organization .

wdt:RoleInFreelance a wikibase:Property ;
    schema:description "The position or function the subject held during freelance work." ;
    rdfs:label "role in freelance" ;
    rdfs:domain wd:Person ;
    rdfs:range rdfs:Literal .

wdt:duration_of_freelance_role a wikibase:Property ;
    schema:description "The time period in which the freelance work was carried out." ;
    rdfs:label "duration of freelance role" ;
    rdfs:domain wd:freelance_role ;
    rdfs:range xsd:duration .

wdt:CarbonTrackingTool a wikibase:Property ;
    schema:description "The tool used to measure and track carbon footprint in a project." ;
    rdfs:label "carbon tracking tool" ;
    rdfs:domain wd:project, wd:environmental_assessment, wd:carbon_footprint_study ;
    rdfs:range wd:software_tool, wd:carbon_measurement_tool, wd:environmental_monitoring_system .

wdt:locationOfOrganization a wikibase:Property ;
    rdfs:label "location of organization" ;
    rdfs:comment "The city where the project organization is located." ;
    rdfs:domain wd:Organization ;
    rdfs:range wd:City .

wdt:MicrocontrollerUsed a wikibase:Property ;
    rdfs:label "microcontroller used" ;
    rdfs:comment "The specific microcontroller used in a project." ;
    rdfs:domain wd:Project, wd:ElectronicDevice, wd:EmbeddedSystem ;
    rdfs:range wd:Microcontroller, wd:IntegratedCircuit, wd:Processor .

wdt:Course a wikibase:Property ;
    schema:description "A specific academic subject or set of subjects taken by the subject." ;
    rdfs:label "course" ;
    rdfs:domain wd:Person ;
    rdfs:range wd:AcademicSubject .

wdt:Project a wikibase:Property ;
    schema:description "A specific work or development project undertaken by the subject" ;
    rdfs:label "project" ;
    rdfs:domain wd:person, wd:organization, wd:government, wd:company ;
    rdfs:range wd:project, wd:initiative, wd:program, wd:development_program .

wdt:courseName a wikibase:Property ;
    rdfs:label "course name" ;
    rdfs:comment "The title of a specific academic course completed by the subject." ;
    rdfs:domain wd:Person ;
    rdfs:range xsd:string .

wdt:P1 a wikibase:Property ;
    rdfs:label "presentation title"@en ;
    schema:description "The title of a seminar or technical presentation delivered by the subject."@en ;
    rdfs:domain wd:Presentation, wd:Seminar, wd:TechnicalPresentation ;
    rdfs:range xsd:string .

wdt:University a wikibase:Property ;
    schema:description "The institution where the subject is currently studying." ;
    rdfs:label "university" ;
    rdfs:domain wd:Person ;
    rdfs:range wd:EducationalOrganization .

wdt:startDate a wikibase:Property ;
    schema:description "The date on which the subject began a program or position." ;
    rdfs:label "start date" ;
    rdfs:domain wd:position, wd:program, wd:employment, wd:role ;
    rdfs:range xsd:date .

wdt:endDate a wikibase:Property ;
    rdfs:label "endDate" ;
    rdfs:domain wd:Program, wd:Position, wd:Tenure, wd:Employment ;
    rdfs:range xsd:date ;
    schema:description "The date on which the subject ended a program or position." .

wdt:percentageOfMarks a wikibase:Property ;
    rdfs:label "percentage of marks" ;
    schema:description "The percentage of marks achieved by the subject in an academic program." ;
    rdfs:domain wd:AcademicProgram, wd:Student, wd:Assessment ;
    rdfs:range xsd:float .

wdt:CurrentStatus a wikibase:Property ;
    rdfs:label "current status" ;
    rdfs:comment "The current employment or project status of the subject." ;
    rdfs:domain wd:Person, wd:Organization, wd:Project ;
    rdfs:range wd:EmploymentStatus, wd:ProjectStatus, wd:ActivityStatus .

wdt:MultiAgentCoordinationFramework a wikibase:Property ;
    rdfs:label "multiAgentCoordinationFramework" ;
    schema:description "The name of a collaborative system or architecture being developed by the subject." ;
    rdfs:domain wd:Person, wd:Organization, wd:ResearchProject ;
    rdfs:range rdfs:Literal .

wdt:fullName a wikibase:Property ;
    rdfs:label "fullName" ;
    rdfs:domain wd:Person ;
    rdfs:range xsd:string ;
    schema:description "The full name of the individual." .

wdt:coursesTaken a wikibase:Property ;
    schema:description "The list of courses completed in an academic program." ;
    rdfs:label "courses taken" ;
    rdfs:domain wd:AcademicProgram, wd:Student, wd:EducationRecord ;
    rdfs:range wd:Course, wd:CompletedCourse, wd:AcademicSubject .

wdt:CurrentStatusOfRole a wikibase:Property ;
    schema:description "Whether a role is ongoing or completed." ;
    rdfs:label "current status of role" ;
    rdfs:domain wd:Role ;
    rdfs:range wd:Status .

wdt:nameOfFScProgram a wikibase:Property ;
    schema:description "The name of the intermediate (FSc) program" ;
    rdfs:label "name of FSc program" ;
    rdfs:domain wd:EducationProgram ;
    rdfs:range xsd:string .

wdt:marksAchievedInFSc a wikibase:Property ;
    rdfs:label "marks achieved in FSc" ;
    rdfs:comment "The marks obtained in the FSc program." ;
    rdfs:domain wd:student ;
    rdfs:range xsd:integer .

wdt:nameOfMatriculationProgram a wikibase:Property ;
    schema:description "The name of the matriculation program completed." ;
    rdfs:label "name of matriculation program" ;
    rdfs:domain wd:Person, wd:Education ;
    rdfs:range rdfs:Literal .

wdt:marksAchievedInMatriculation a wikibase:Property ;
    schema:description "The marks obtained in the matriculation program." ;
    rdfs:label "marks achieved in matriculation" ;
    rdfs:domain wd:Person, wd:Student ;
    rdfs:range xsd:float, xsd:integer, xsd:string .

wdt:simulationEngineered a wikibase:Property ;
    rdfs:label "simulationEngineered" ;
    rdfs:domain wd:individual ;
    rdfs:range wd:simulation ;
    schema:description "The specific simulation developed by the individual." .

wdt:AlgorithmsImplemented a wikibase:Property ;
    rdfs:label "algorithms implemented" ;
    rdfs:comment "The specific algorithms used in the simulation or project." ;
    rdfs:domain wd:Simulation, wd:Project, wd:SoftwareImplementation ;
    rdfs:range wd:Algorithm, wd:ComputationalMethod, wd:MachineLearningModel .

wdt:StatusOfProject a wikibase:Property ;
    rdfs:label "StatusOfProject" ;
    rdfs:domain wd:project, wd:framework_development ;
    rdfs:range wd:project_status, wd:development_stage ;
    schema:description "The current state or progress of the project or framework being developed." .
